<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title" v-if="IsFor=='Company'">{{ $t('AddCompanyHolidayManual') }} </h4>
                        <h4 class="modal-title" v-if="IsFor=='Update'">{{ $t('Update') }} {{ $t('Holiday') }} {{ $t('Manual') }} </h4>
                        <h4 class="modal-title" v-if="IsFor=='Clone'">{{ $t('CloneHoliday') }} </h4>
                        <button type="button" class="close" v-on:click="CloseAddContract">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>  
                        <span class="user-guide">
                            <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG"
                                role="button" aria-expanded="false" aria-controls="collapseExample"> <em
                                    class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                            <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                    <div class="con" v-html="getUserGuideTitle()"></div>
                                </div>
                            </div>
                        </span>                      
                    </div>
                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AssignTagForm" :mandatorytext='MandatoryString'
                            v-on:OnSubmit="OnSubmit">
                        </dynamic-form>
                    </div>   
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import {  TreeSelectField } from 'tg-controls_cli/dist/myLib.common'
import DataService from '../../../services/DataService';
export default {
    components: {
        'tree-view': TreeSelectField
    },
    props: {
        UserId: {
            type: Number
        },
        ContractHolidayData:{
            type:Object
        },
        IsFor:{
            type:String
        }
    },
    data(){
        return{
            isLoading:false, 
            HolidayId:0,
            FinalLocationData:[],       
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            FormSchema: [               
                {
                    layoutType: "four",
                    Data: [
                        {
                            astype: "TextField",                                                
                            label: this.$t('name'),
                            name: "Name",
                            value: "",               
                            placeholder: this.$t('Enter Name'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "DateField",                                                
                            label: this.$t('Date'),
                            config: {
                              format: "MM/DD/YYYY",
                            },
                            name: "Date",
                            value: "",                           
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "RadioField",
                            label: this.$t('HolidayType'),
                            name: "HodlidayType",
                            value: "1",
                            placeholder: "",
                            config: {
                                options: [{
                                    name: this.$t('Fixed'), value: 1
                                }, {
                                    name: this.$t('Observed'), value: 0
                                }],
                                showAddIcon: false
                                
                            },
                            validationRules: { "required": false },
                        },
                        {
                            astype: "ToggleField",
                            label: this.$t('Recurring'),
                            name: "Recurring",
                            value: "1",
                            visibility: true,
                            config: {
                                options: [{ name: 'Yes', value: 1 }, { name: 'No', value: 0 }],
                                showAddIcon: false,
                            }
                        },  
                        {
                            astype: "toggleField",
                            label: this.$t('AddToHolidayBank'),
                            name: "AddToHolidayBank",
                            value: "",
                            placeholder: "",
                            config: {
                                options: [{value:'1'}],
                                showAddIcon: false                               
                            },
                            validationRules: "",
                        }, 
                        {
                            astype: "RadioField",
                            label: this.$t('Duration'),
                            name: "Duration",
                            value: "1",
                            visibility: true,
                            config: {
                                options: [{ name: this.$t('FullDay'), value: 1 }, { name: this.$t('PartialDay'), value: 0 }],                                
                                onChange: this.onChangeRadio
                            }
                        },
                        {
                            astype: "DateField",                                                
                            label: this.$t('StartTime'),
                            name: "StartTime",
                            value: null,  
                            visibility: false,
                             config: {
                                    mode: "time",
                                    is24hr: true,
                                // format: "hh:mm",
                                    
                                },                                                       
                            placeholder: this.$t('Select Start Time'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "DateField",                                                
                            label: this.$t('EndTime'),
                            name: "EndTime",
                            value: null,  
                            visibility: false,
                             config: {
                                    mode: "time",
                                    is24hr: true,
                                // format: "hh:mm",
                                    
                                },                                                        
                            placeholder: this.$t('Select End Time'),
                            validationRules: { "required": true, max: 100 },
                        },
                         {
                        astype: "SearchableSelectField",
                        label: this.$t('Location'),
                        name: "Location",
                        value: "",
                        placeholder: "Select Location",
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            actionButtons: {
                            selectAll: true,
                            clear: true},
                            groupFields: [],
                            isMultiple: true,
                            minSearchLength: 0,
                            statusFieldConfig: {
                                fieldName: 'status',
                                activeValues: ['Active', 'active'],
                                inactiveValues: ['Inactive', 'inactive'],
                                activeColor: '#28a745',
                                inactiveColor: '#dc3545'
                            },
                        },
                        validationRules: {
                            "required": true
                        },
                    },                    
                        {
                            astype: "SelectField",                                                
                            label: this.$t('Status'),
                            name: "Status",
                            value: "",  
                            config: {
                                options: []
                            },                           
                            placeholder: this.$t('Select Status'),
                            validationRules: { "required": true, max: 100 },
                        }                                          
                    ]
                },                
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",                 
                            label: this.$t('DESCRIPTION'),
                            name: "Description",
                            value: "",  
                            validationRules: { "required": false, max: 4000 },
                            config: {
                                rows:5
                            }
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:true
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.CloseAddContract,
                },
            ], 
        }
    },
    created: async function(){
        var ths =this;    
        ths.UserId=ths.$route.params.id;
        await ths.CompanyHolidayMultipleLocation();
        ths.GetStatusList();
        if(ths.ContractHolidayData != null){
            setTimeout(() => {
                ths.BindHolidayData(ths.ContractHolidayData);
            }, 200); 
        }        
        setTimeout(() => {
            ths.$refs.AssignTagForm.UpdateKeyValue();
        }, 200); 
        
    },
    methods:{
        GetStatusList:function(){            
            var ths=this;
            var url=`statusType=Category&hasglobal=true&langCode=en`
            DataService.GetStatusList(url).then((response)=>{            
                if(response.data.result.length>0){
                    var statusData=response.data.result;
                    statusData.forEach(element => {
                        var Obj={
                            name:element.STATUS,
                            value:element.STATUS_ID
                        }
                        ths.FormSchema[0].Data[9].config.options.push(Obj);
                    });
                    ths.$refs.AssignTagForm.UpdateKeyValue();
                }
            });
        },
        async CompanyHolidayMultipleLocation(){
                var vm = this;    
                var LocationData=[];
                var url=`RequestFrom=${'COMPANY_LOCATIONS'}`;
                await DataService.CompanyHolidayMultipleLocation(url).then(function (response) {
                vm.FinalLocationData  = response.data.result;
                if (response.data.result.length > 0) {
                            response.data.result.forEach(element => {                        
                                vm.FormSchema[0].Data[8].config.options.push({
                                     description: null,
                                    displayValue: element.LOCATION_NAME,
                                    groupText: null,
                                    groupValue: null,
                                    metaData: null,
                                    text: element.LOCATION_NAME,
                                    value: element.COMPANY_LOCATION_ID
                                })
                            });
                             setTimeout(() => {
                            ths.$refs.AssignTagForm.UpdateKeyValue();
                        }, 200); 
                        }   
            });
        }, 
        getUserGuideTitle() {
            let text = this.$t('User_Guide_Company_Holiday');

            return text
                // 🔥 IMPORTANT: escaped characters
                .replace(/\\n/g, '')
                .replace(/\\t/g, '&nbsp;');
        },     
        getChildLocation (locationId, currentItem, data) { 
            var vm=this;
            let treeArray={};
            treeArray={
                id:currentItem.COMPANY_LOCATION_ID,
                label:currentItem.LOCATION_NAME
            }
            let retrunArray = treeArray;
            var childArray = data.filter(function (el) {
                return el.PARENT_LOCATION_ID == locationId;
            });
            let finalChildArray = [];
            childArray.forEach((value) => {
                let ChildfolderId = value.COMPANY_LOCATION_ID
                var CheckIfExist1 = finalChildArray.filter(function (el) {
                    return el.COMPANY_LOCATION_ID == value.COMPANY_LOCATION_ID;
                });
                if (CheckIfExist1.length == 0) {
                    var CheckIfExist = data.filter(function (el) {
                        return el.PARENT_LOCATION_ID == ChildfolderId;
                    });
                    if (CheckIfExist != null && CheckIfExist.length > 0) {
                        let rslt = vm.getChildLocation(ChildfolderId, value, data);                                              
                        finalChildArray.push(rslt);
                    } else {                        
                        treeArray={
                            id:`${value.COMPANY_LOCATION_ID}`,
                            label:`${value.LOCATION_NAME}`
                        }
                        finalChildArray.push(treeArray);
                    }
                }
            });
            retrunArray.children = finalChildArray;
            return retrunArray;
        },  
        BindHolidayData(val){            
            var ths = this;
            ths.HolidayId=val.holidayid;          
            ths.FormSchema[0].Data[0].value=val.holidayname;
            ths.FormSchema[0].Data[1].value=ths.IsFor=='Clone'?'': val.holidaydate;
            ths.FormSchema[0].Data[2].value=val.isFixed==true?1:0;
            ths.FormSchema[0].Data[3].value=val.isrecurring==true?1:0;
            ths.FormSchema[0].Data[4].value= (val.isManual==true && val.holiday_Bank_Id !=0)==true ? 1:0;
            if(!val.isfullday){
                ths.FormSchema[0].Data[6].visibility=true;
                ths.FormSchema[0].Data[7].visibility=true;
            }else{
                ths.FormSchema[0].Data[6].visibility=false;
                ths.FormSchema[0].Data[7].visibility=false;
            }
            ths.FormSchema[0].Data[5].value=val.isfullday==true?1:0;
            ths.FormSchema[0].Data[6].value=val.fromtime;
            ths.FormSchema[0].Data[7].value=val.totime;
            if(val.companylocation != ''){
                // Clean and split the string into an array of location names
                const locationNames = val.companylocation
                    .split(',')  
                    .map(name => name.trim())  
                    .filter(name => name !== '');  
                
                // Get COMPANY_LOCATION_ID for each location name
                const locationIdsArray = locationNames.map(locationName => {
                    const location = ths.FinalLocationData.find(item => 
                        item.LOCATION_NAME === locationName
                    );
                    return location ? location.COMPANY_LOCATION_ID : null;
                })
                .filter(id => id !== null); 
                  ths.$nextTick(() => {
                            ths.$refs.AssignTagForm.updateProperty("Location", "value", locationIdsArray);
                            ths.$refs.AssignTagForm.UpdateKeyValue();
                 });
            }
            //ths.FormSchema[0].Data[8].value=val.companylocation.split(',')[0];
            ths.FormSchema[0].Data[9].value=val.statusid;
            ths.FormSchema[1].Data[0].value=val.holidaydescription;
        },
        CloseAddContract(){
            var vm=this;
            vm.$emit('CloseAddContract');
        },
        onChangeRadio(){
            var ths= this;
            var chkValue=ths.FormSchema[0].Data[5].value;
            if(chkValue==0){
                ths.FormSchema[0].Data[6].visibility=true;
                ths.FormSchema[0].Data[7].visibility=true;
            }else{
                ths.FormSchema[0].Data[6].visibility=false;
                ths.FormSchema[0].Data[7].visibility=false;
            }
        },
        OnSubmit(){
            var ths = this;
            var params = '';
            if(ths.IsFor == 'Update'){
                params = 'controller=HR&action=EditCompanyHoliday';
            } else {
                params = 'controller=HR&action=CompanyHoliday';
            }
            DataService.CheckPrivilege(params).then(function (response) {
                if(response.data){
                    let obj={
                        HolidayId:ths.HolidayId,
                        HolidayName:ths.FormSchema[0].Data[0].value,
                        HolidayDate:ths.FormSchema[0].Data[1].value,
                        HolidayType:ths.FormSchema[0].Data[2].value,
                        Recurring:ths.FormSchema[0].Data[3].value,
                        AddToHolidayBank:ths.FormSchema[0].Data[4].value[0]||'',
                        Duration:ths.FormSchema[0].Data[5].value,
                        StartTime:ths.FormSchema[0].Data[5].value==1?null:ths.FormSchema[0].Data[6].value,
                        EndTime:ths.FormSchema[0].Data[5].value==1?null:ths.FormSchema[0].Data[7].value,
                        LocationId:ths.FormSchema[0].Data[8].value.join(','),
                        StatusId:ths.FormSchema[0].Data[9].value||1001,
                        Description:ths.FormSchema[1].Data[0].value,
                        ClientId:ths.UserId,
                        IsForContract:1,
                        IsForCompany:0,
                        ReqForm:'Company',
                        ISFULLDAY:ths.FormSchema[0].Data[5].value=='1'?1:0,
                        ForClone: ths.IsFor=='Clone'?1: 0
                    }
                    var JsonObj=JSON.stringify(obj);
                    DataService.SaveCompanyHoliday(JsonObj).then((response)=>{
                        if(response.status==200){
                            if(ths.HolidayId>0){
                                ths.ShowAlert(ths.$t('UpdatedSuccess',[ths.$t('CompanyHoliday')]),"success", true, ths.$t("Alert"));
                            }else{
                                ths.ShowAlert(ths.$t('AddedSuccess',[ths.$t('CompanyHoliday')]),"success", true, ths.$t("Alert"));
                            }                                    
                            ths.CloseAddContract();                    
                        }
                    })
                }
                else{
                    ths.ShowAlert(ths.$t('NotAuthorizedSection'), "failure", true, "Alert");
                    return false;
                }
            });
        }
    }
}
</script>
<style scoped>
.switch {width: 71px;}
</style>